mapper.select:
SELECT t.id, t.asset_name, t.asset_code, t.asset_no, t.asset_type, t.asset_sub_type, t.amount, t.invest_amount, t.asset_status, t.remark, t.asset_owner, t.update_time, t.update_by, i.name AS assetOwnerName FROM t_asset_ledger t LEFT JOIN t_sys_person_info i ON i.account_id = t.asset_owner WHERE t.asset_owner = #{assetOwner}
AND t.asset_type = #{assetType}
ORDER BY t.update_time DESC

SELECT t.id, t.asset_name, t.asset_code, t.asset_no, t.asset_type, t.asset_sub_type, t.amount, t.invest_amount, t.asset_status, t.remark, t.asset_owner, t.update_time, t.update_by, i.name AS assetOwnerName FROM t_asset_ledger t LEFT JOIN t_sys_person_info i ON i.account_id = t.asset_owner WHERE t.asset_owner = #{assetOwner}
AND t.asset_type = #{assetType}
AND t.asset_sub_type = #{assetSubType}
AND t.asset_status = 4
AND t.asset_status != 4
ORDER BY t.update_time DESC

SELECT (SELECT d.`value` FROM t_sys_dict d WHERE d.type = CONCAT('asset_type_', #{assetType}) AND d.`code` = asset_sub_type LIMIT 1) TEXT,
       sum(amount) VALUE
FROM t_asset_ledger
WHERE asset_owner = #{assetOwner}
  AND asset_type = #{assetType}
GROUP BY asset_sub_type
